@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <div class="form-field">
            <label>Title</label>
            <input type="text" @bind="title" placeholder="Task title" />
        </div>
        <div class="form-field">
            <label>Assignee</label>
            <input type="text" @bind="assignee" placeholder="Assignee name" />
        </div>
        <div class="form-field">
            <label>Priority</label>
            <select @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="form-field">
            <label>Due Date</label>
            <input type="date" @bind="dueDate" />
        </div>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="form-error">@errorMessage</div>
        }
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@isSaving">
                @(isSaving ? "Saving..." : "Save")
            </button>
            <button class="btn-cancel" @onclick="Cancel" disabled="@isSaving">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            ResetForm();
            IsVisible = false;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
        errorMessage = null;
    }
}

