    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTextChanged.InvokeAsync(value);
    }
}
"}

{"path": "/tmp/sv-39af55a844734c8aa8889a849c6bb83e/Components/Board/BoardColumn.razor", "file_text": "<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>
    <div class="column-cards">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => MoveTask(task.Id, LeftStatus!)"
                      OnMoveRight="() => MoveTask(task.Id, RightStatus!)" />
        }
    </div>
    <AddTaskForm DefaultStatus="@ColumnName" OnTaskCreated="OnTaskCreated" />
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = default!;
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool ShowMoveLeft => LeftStatus is not null;
    private bool ShowMoveRight => RightStatus is not null;
    private int? movingTaskId;

    private async Task MoveTask(int taskId, string newStatus)
    {
        movingTaskId = taskId;
        try
        {
            await OnMoveTask.InvokeAsync((taskId, newStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }
}
"}

