{"file_text": "@page "/board"
@rendermode InteractiveServer

@using sv_39af55a844734c8aa8889a849c6bb83e.Components.Board

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p class="board-loading">Loading tasks…</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" SearchTextChanged="text => { searchText = text; }" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     RightStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     LeftStatus="To Do"
                     RightStatus="Done"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     LeftStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    [Inject] private ITaskService TaskService { get; set; } = default!;

    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var index = allTasks.FindIndex(t => t.Id == move.TaskId);
            if (index >= 0)
            {
                var old = allTasks[index];
                allTasks[index] = old with { Status = move.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}
